export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  const seriesArr =
    inputs?.avgCpuMetrics?.timeseries ?? inputs?.avgCpuMetrics;
  if (!Array.isArray(seriesArr)) return 0;

   return seriesArr.reduce((globalMax, { data }) => {
    if (!Array.isArray(data)) return globalMax;

    const localMax = data.reduce((m, { average }) =>
      typeof average === 'number' && average > m ? average : m
    , 0);

    return localMax > globalMax ? localMax : globalMax;
  }, 0);
};

export const code = async (inputs) => {
  const seriesArr =
    inputs?.maxCpuMetrics?.timeseries ?? inputs?.maxCpuMetrics;
  if (!Array.isArray(seriesArr)) return 0;

  return seriesArr.reduce((max, series) => {
    if (!Array.isArray(series?.data)) return max;

    const seriesMax = series.data.reduce((m, p) => {
      return typeof p?.maximum === "number" && p.maximum > m ? p.maximum : m;
    }, 0);

    return seriesMax > max ? seriesMax : max;
  }, 0);
};

export const code = async (inputs) => {
  const toSeriesArr = (metric) => {
    if (!metric) return [];
    if (Array.isArray(metric) && metric.length) {
      if (metric[0]?.data) return metric;
      return metric.flatMap(toSeriesArr);
    }
    if (Array.isArray(metric.timeseries)) return metric.timeseries;
    if (Array.isArray(metric.value)) return metric.value.flatMap(toSeriesArr);
    return [];
  };

  const inSeries  = toSeriesArr(inputs?.networkInMetrics);
  const outSeries = toSeriesArr(inputs?.networkOutMetrics);

  const buckets = new Map();

  const addSeries = (seriesArr) => {
    seriesArr.forEach(({ data = [] }) =>
      data.forEach(({ timeStamp, average }) => {
        if (typeof average !== 'number' || !timeStamp) return;
        buckets.set(timeStamp, (buckets.get(timeStamp) || 0) + average);
      })
    );
  };

  addSeries(inSeries);
  addSeries(outSeries);

  let maxBps = 0;
  for (const v of buckets.values()) if (v > maxBps) maxBps = v;

  return (maxBps * 3600) / (1024 * 1024); // MB/h
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;
  const currency = prices[0][2];

  return {
    average,
    currency,
  };
};
